mapper.select:
select

from teacher_schedule
where week_day = #{weekDay}
and status = #{status}
order by start_time asc

select

from teacher_schedule
where teacher_account = #{teacherAccount}
and status = #{status}
order by week_day asc, start_time asc

select

from teacher_schedule
where teacher_account = #{teacherAccount}
and week_day = #{weekDay}
and status = #{status}
order by start_time asc

select

from teacher_schedule
where id = #{id}
and teacher_account = #{teacherAccount}
limit 1

select count(1)
from teacher_schedule
where teacher_account = #{teacherAccount}
  and week_day = #{weekDay}
  and start_time = #{startTime}
  and end_time = #{endTime}
  and status = #{status}

select count(1)
from teacher_schedule
where teacher_account = #{teacherAccount}
  and week_day = #{weekDay}
  and start_time = #{startTime}
  and end_time = #{endTime}
  and status = #{status}
  and id != #{id}

select

from teacher_schedule
where teacher_account = #{teacherAccount}
and week_day = #{weekDay}
and start_time = #{startTime}
and end_time = #{endTime}
and status = #{status}
limit 1
